async (page) => {
  // Try to directly trigger warp via game internals
  const result = await page.evaluate(() => {
    try {
      // Show the warp container first
      const warpContainer = document.getElementById('warp0')?.closest('[id*="warp"]') || 
                           document.getElementById('warp0')?.parentElement;
      if (warpContainer) {
        warpContainer.style.display = 'block';
      }
      // Try the warp menu's show method
      const warp = window.game?.menu?.warp;
      if (warp) {
        warp.show();
        return { showed: true, warpExists: true };
      }
      return { showed: false, error: 'no warp menu' };
    } catch(e) {
      return { error: e.message };
    }
  });
  await page.waitForTimeout(1000);

  // Check parent visibility now
  const parentVis = await page.evaluate(() => {
    const btn = document.getElementById('warp0');
    return btn ? window.getComputedStyle(btn.parentElement).display : 'not found';
  });

  // Click warp0
  await page.evaluate(() => document.getElementById('warp0').click());
  await page.waitForTimeout(4000);

  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  return JSON.stringify({ result, parentVis, pos: parsed.player_position });
}

