    const r = await page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), {x: targetX, y: targetY});
    await page.waitForTimeout(4000);

    const vg = p.nearby_entities.find(e => e.name === 'Village Girl');
    if (vg && vg.distance <= 2) break;

    const s2 = await page.evaluate(() => JSON.stringify(window.__latestGameState));
    const p2 = JSON.parse(s2);
    const vg2 = p2.nearby_entities.find(e => e.name === 'Village Girl');
    if (vg2 && vg2.distance <= 2) break;
  }

